patch:
--- a/sync_counter.v
+++ b/sync_counter.v
@@ -1,6 +1,6 @@
 module synchronous_counter_32bit(
   input clk,
   input rst_n,
   output reg [31:0] count
 );
-  always @(posedge clk) begin
+  always @(posedge clk or negedge rst_n) begin
     if (!rst_n)
       count <= 32'h0;
     else

before_code:
module synchronous_counter_32bit(
  input clk,
  input rst_n,
  output reg [31:0] count
);
  always @(posedge clk) begin
    if (!rst_n)
      count <= 32'h0;
    else
      count <= count + 1;
  end
endmodule

after_code:
module synchronous_counter_32bit(
  input clk,
  input rst_n,
  output reg [31:0] count
);
  always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
      count <= 32'h0;
    else
      count <= count + 1;
  end
endmodule
